using System;

class Program
{
    static void Main()
    {
        int price = 20;
        int quantity = 3;

        int total = CalculateTotal(price, quantity);

        Console.WriteLine("Total price: " + total);
    }

    static int CalculateTotal(int price, int quantity)
    {
        int result = price * quantity;
        return result;
    }
}
